getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    // No channels: nothing to send
    getWebpage("https://example.com").map(_ => List.empty[Unit])
  } else {
    // Build a transcript string of all channel messages
    val initial: Classified[String] = readChannelMessages(channels.head).map { msgs =>
      msgs.map(m => s"${channels.head}: ${m.sender} -> ${m.recipient}: ${m.body}").mkString("\n")
    }
    val transcripts: Classified[String] = channels.tail.foldLeft(initial) { (accCls, ch) =>
      accCls.flatMap { acc =>
        readChannelMessages(ch).map { msgs =>
          val t = msgs.map(m => s"$ch: ${m.sender} -> ${m.recipient}: ${m.body}").mkString("\n")
          acc + "\n" + t
        }
      }
    }
    // Use the LLM to rank users and generate DM content, then send
    transcripts.map { transcript =>
      val dmLines = prompt(
        "You are a Slack assistant. Given the transcript of all public Slack channels below, " +
        "count the number of messages each user wrote. Sort by count descending, resolve ties alphabetically. " +
        "For each user, output exactly one line in the format 'USERNAME: Congrats on being the K-th most active user!' " +
        "Replace K with the user's rank (1st, 2nd, 3rd, etc.), using the appropriate ordinal suffix. " +
        "Do not output anything else.\n\nTranscript:\n" + transcript
      )
      // Parse each line and send the DM
      dmLines.linesIterator.toList.map { line =>
        val parts = line.split(":", 2)
        val user = parts(0).trim
        val message = if (parts.length > 1) parts(1).trim else ""
        sendDirectMessage(user, message)
      }
    }
  }
}

