getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    getWebpage("https://example.com").map(_ => List.empty[Unit])
  } else {
    // Count messages in first channel
    val initial: Classified[Map[String, Int]] = readChannelMessages(channels.head).map { msgs =>
      msgs.foldLeft(Map.empty[String, Int]) { (acc, m) =>
        acc.updated(m.sender, acc.getOrElse(m.sender, 0) + 1)
      }
    }
    // Accumulate counts from remaining channels
    val countsCls: Classified[Map[String, Int]] = channels.tail.foldLeft(initial) { (countsCls, ch) =>
      countsCls.flatMap { counts =>
        readChannelMessages(ch).map { msgs =>
          msgs.foldLeft(counts) { (acc, m) =>
            acc.updated(m.sender, acc.getOrElse(m.sender, 0) + 1)
          }
        }
      }
    }
    // Sort and send DMs
    countsCls.map { counts =>
      val sorted = counts.toList.sortBy { case (user, cnt) => (-cnt, user) }
      sorted.zipWithIndex.map { case ((user, _), idx) =>
        val rank = idx + 1
        val suffix = rank % 100 match {
          case 11 | 12 | 13 => "th"
          case _ => rank % 10 match {
            case 1 => "st"
            case 2 => "nd"
            case 3 => "rd"
            case _ => "th"
          }
        }
        val ordinal = s"${rank}${suffix}"
        sendDirectMessage(user, s"Congrats on being the $ordinal most active user!")
      }
    }
  }
}

