getChannels().flatMap { channels =>
  // Start with an empty count list inside Classified
  val initialCounts: Classified[List[(String, Int)]] = getWebpage("http://example.com").map(_ => Nil: List[(String, Int)])
  // Accumulate counts across all channels
  val countsCls = channels.foldLeft(initialCounts) { (countsCls, ch) =>
    countsCls.flatMap { counts =>
      readChannelMessages(ch).map { msgs =>
        msgs.foldLeft(counts) { (acc, m) =>
          val idx = acc.indexWhere(_._1 == m.sender)
          if (idx < 0) acc :+ (m.sender, 1)
          else acc.updated(idx, (m.sender, acc(idx)._2 + 1))
        }
      }
    }
  }
  // Sort and send DMs
  countsCls.map { counts =>
    val sorted = counts.sortWith { case ((u1, c1), (u2, c2)) =>
      if (c1 != c2) c1 > c2 else u1 < u2
    }
    sorted.zipWithIndex.map { case ((user, _), idx) =>
      val rank = idx + 1
      val suffix = rank % 100 match {
        case 11 | 12 | 13 => "th"
        case _ => rank % 10 match {
          case 1 => "st"
          case 2 => "nd"
          case 3 => "rd"
          case _ => "th"
        }
      }
      val ordinal = s"${rank}${suffix}"
      sendDirectMessage(user, s"Congrats on being the $ordinal most active user!")
    }
  }
}

